class Solution {
    public long countGoodIntegers(int n, int k) {
        long res = 0;
        for (int i = 1; i <= k; i++) {
            long ways = factorial(k - 1);
            for (int j = 1; j <= n - k; j++) {
                ways *= factorial(j - 1);
            }
            res += ways;
        }
        return res;
    }

    private long factorial(int n) {
        long res = 1;
        for (int i = 2; i <= n; i++) {
            res *= i;
        }
        return res;
    }
}
